"use client";

import { motion } from "framer-motion";
import { useViewMode } from "@/context/view-mode-context";

const techStack = [
  { name: "Linux", category: "OS", icon: "🐧" },
  { name: "Docker", category: "Containers", icon: "🐳" },
  { name: "Kubernetes", category: "Orchestration", icon: "☸️" },
  { name: "Terraform", category: "IaC", icon: "🏗️" },
  { name: "AWS", category: "Cloud", icon: "☁️" },
  { name: "GitHub Actions", category: "CI/CD", icon: "⚙️" },
  { name: "Bash", category: "Scripting", icon: "💻" },
  { name: "Nginx", category: "Web Server", icon: "🌐" },
  { name: "Git", category: "Version Control", icon: "📦" },
  { name: "Networking", category: "Infrastructure", icon: "🔗" },
  { name: "HTML", category: "Frontend", icon: "📄" },
  { name: "CSS", category: "Frontend", icon: "🎨" },
  { name: "JavaScript", category: "Programming", icon: "⚡" },
];

const techIcons: Record<string, JSX.Element> = {
  Linux: <LinuxIcon />,
  Docker: <DockerIcon />,
  Kubernetes: <KubernetesIcon />,
  Terraform: <TerraformIcon />,
  AWS: <AWSIcon />,
  "GitHub Actions": <GitHubActionsIcon />,
  Bash: <BashIcon />,
  Nginx: <NginxIcon />,
  Git: <GitIcon />,
  Networking: <NetworkingIcon />,
  HTML: <HTMLIcon />,
  CSS: <CSSIcon />,
  JavaScript: <JavaScriptIcon />,
};

export function TechStackSection() {
  const { mode } = useViewMode();

  return (
    <section id="stack" className="py-24 relative">
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-primary/5 to-transparent" />

      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5 }}
        >
          <h2 className="text-3xl font-bold text-foreground mb-2">
            {mode === "hr" ? "Tech Stack" : "// Tech_Stack"}
          </h2>
          <div className="w-16 h-1 bg-primary rounded-full mb-4" />
          <p className="text-muted-foreground mb-12 max-w-2xl">
            {mode === "hr"
              ? "The technologies and tools I work with daily to build and maintain cloud infrastructure."
              : "Core technologies in my infrastructure toolkit"}
          </p>
        </motion.div>

        {mode === "hr" ? <HRTechStack /> : <TechnicalTechStack />}
      </div>
    </section>
  );
}

function HRTechStack() {
  const categories = [...new Set(techStack.map((t) => t.category))];

  return (
    <div className="space-y-12">
      {categories.map((category, catIndex) => (
        <motion.div
          key={category}
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5, delay: catIndex * 0.1 }}
        >
          <h3 className="text-sm font-medium text-muted-foreground mb-4 uppercase tracking-wider">
            {category}
          </h3>
          <div className="flex flex-wrap gap-3">
            {techStack
              .filter((t) => t.category === category)
              .map((tech, index) => (
                <motion.div
                  key={tech.name}
                  initial={{ opacity: 0, scale: 0.9 }}
                  whileInView={{ opacity: 1, scale: 1 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.3, delay: index * 0.05 }}
                  whileHover={{ y: -2, scale: 1.02 }}
                  className="glass px-4 py-3 rounded-xl flex items-center gap-3 hover:border-primary/50 transition-all cursor-default"
                >
                  <div className="w-8 h-8 flex items-center justify-center text-primary">
                    {techIcons[tech.name]}
                  </div>
                  <span className="font-medium text-foreground">
                    {tech.name}
                  </span>
                </motion.div>
              ))}
          </div>
        </motion.div>
      ))}
    </div>
  );
}

function TechnicalTechStack() {
  return (
    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
      {techStack.map((tech, index) => (
        <motion.div
          key={tech.name}
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.3, delay: index * 0.05 }}
          whileHover={{ scale: 1.02 }}
          className="glass rounded-xl p-4 hover:border-primary/50 transition-all group"
        >
          <div className="flex items-center gap-3 mb-3">
            <div className="w-10 h-10 flex items-center justify-center text-primary group-hover:scale-110 transition-transform">
              {techIcons[tech.name]}
            </div>
            <div>
              <h4 className="font-mono text-sm text-foreground">{tech.name}</h4>
              <p className="text-xs text-muted-foreground font-mono">
                {tech.category}
              </p>
            </div>
          </div>
          <div className="h-1 bg-secondary rounded-full overflow-hidden">
            <motion.div
              initial={{ width: 0 }}
              whileInView={{ width: `${60 + Math.random() * 40}%` }}
              viewport={{ once: true }}
              transition={{ duration: 1, delay: index * 0.05 }}
              className="h-full bg-primary rounded-full"
            />
          </div>
        </motion.div>
      ))}
    </div>
  );
}

